/**
 * Downloads hero, editorial, and product JPEGs for the e-commerce demo.
 * Portfolio modal screenshots are generated by the real app — run:
 *   npm run build && npm run capture:ecommerce-screenshots
 *
 * Run: node scripts/download-ecommerce-assets.mjs
 */
import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";
import https from "https";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const root = path.join(__dirname, "..");
const base = path.join(root, "public", "images", "ecommerce-demo");

/**
 * Product photos matched to SKU names (Unsplash).
 * p1 headphones · p2 watch · p3 ceramic mugs · p4 canvas tote · p5 laptop on stand ·
 * p6 linen/bedding · p7 running shoes · p8 classic desk lamp (centered, 4:3-safe crop)
 */
const downloads = [
  ["hero.jpg", "https://images.unsplash.com/photo-1441986300917-64674bd600d8?auto=format&fit=crop&w=1920&q=88&fm=jpg"],
  ["editorial/story-1.jpg", "https://images.unsplash.com/photo-1445205170230-053b83016050?auto=format&fit=crop&w=1200&q=88&fm=jpg"],
  ["editorial/story-2.jpg", "https://images.unsplash.com/photo-1490481651871-ab68de25d43d?auto=format&fit=crop&w=1200&q=88&fm=jpg"],
  ["products/p1.jpg", "https://images.unsplash.com/photo-1505740420928-5e560c06d30e?auto=format&fit=crop&w=900&q=88&fm=jpg"],
  ["products/p2.jpg", "https://images.unsplash.com/photo-1523275335684-37898b6baf30?auto=format&fit=crop&w=900&q=88&fm=jpg"],
  ["products/p3.jpg", "https://images.unsplash.com/photo-1602143407151-7111542de6e8?auto=format&fit=crop&w=900&q=88&fm=jpg"],
  ["products/p4.jpg", "https://images.unsplash.com/photo-1574365569389-a10d488ca3fb?auto=format&fit=crop&w=900&q=88&fm=jpg"],
  ["products/p5.jpg", "https://images.unsplash.com/photo-1652198145075-b41c363792d3?auto=format&fit=crop&w=900&q=88&fm=jpg"],
  ["products/p6.jpg", "https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?auto=format&fit=crop&w=900&q=88&fm=jpg"],
  ["products/p7.jpg", "https://images.unsplash.com/photo-1542291026-7eec264c27ff?auto=format&fit=crop&w=900&q=88&fm=jpg"],
  [
    "products/p8.jpg",
    "https://images.unsplash.com/photo-1513506003901-1e6a229e2d15?auto=format&fit=crop&w=900&h=675&q=88&fm=jpg",
  ],
  ["products/p1-b.jpg", "https://images.unsplash.com/photo-1484704849700-f032a568e944?auto=format&fit=crop&w=900&q=88&fm=jpg"],
  ["products/p2-b.jpg", "https://images.unsplash.com/photo-1434056886845-dac89ffe9b56?auto=format&fit=crop&w=900&q=88&fm=jpg"],
];

function fetchFile(url, dest) {
  return new Promise((resolve, reject) => {
    const file = fs.createWriteStream(dest);
    https
      .get(url, { headers: { "User-Agent": "portfolio-asset-fetch/1" } }, (res) => {
        if (res.statusCode === 301 || res.statusCode === 302) {
          file.close();
          fs.unlinkSync(dest);
          return fetchFile(res.headers.location, dest).then(resolve).catch(reject);
        }
        if (res.statusCode !== 200) {
          file.close();
          fs.unlinkSync(dest);
          return reject(new Error(`HTTP ${res.statusCode} for ${url}`));
        }
        res.pipe(file);
        file.on("finish", () => {
          file.close();
          resolve();
        });
      })
      .on("error", (err) => {
        fs.unlink(dest, () => {});
        reject(err);
      });
  });
}

async function main() {
  for (const [rel, url] of downloads) {
    const dest = path.join(base, rel);
    fs.mkdirSync(path.dirname(dest), { recursive: true });
    process.stdout.write(`Fetching ${rel}... `);
    await fetchFile(url, dest);
    const st = fs.statSync(dest);
    console.log(`${st.size} bytes`);
  }
  console.log("Done.");
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
